"use strict";parserFactory.register("sweek.com",()=>new SweekParser);class SweekParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=this.findReadUrl(e),r=t.split("/"),n=r.pop(),o={operationName:null,variables:{storyId:r.pop(),storyDevice:n},query:"query ($storyId: Int!, $storyDevice: String!) {\n  getChapters(storyId: $storyId, storyDevice: $storyDevice) {\n    ok\n    errorCode\n    chapters {\n      id\n      device\n      title\n      __typename\n    }\n    __typename\n  }\n}\n"},s={method:"POST",headers:{Accept:"application/json","Content-Type":"application/json"},credentials:"include",body:JSON.stringify(o)};return(await HttpClient.fetchJson("https://sweek.com/graphql",s)).json.data.getChapters.chapters.map(e=>this.decodeTocJson(t,e))}decodeTocJson(e,t){return{sourceUrl:e+"/"+t.id+"/"+t.device,title:t.title}}findReadUrl(e){return e.querySelector("div.buttonContainer-lMpB3JWLYQC5iY4p4kmh5 a").href}findContent(e){return e.querySelector("div.readingScreenContent-1DcfKpNGB8ryskQn_0vAkM")}extractTitleImpl(e){return e.querySelector("h1")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".actionBar-sVi43NPxX1SfatEP5xyAO"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){let t=e.querySelector("img[alt='Story cover']");return null===t?null:t.src}getInformationEpubItemChildNodes(e){return[e.querySelector("p")]}}